import { streamText } from 'ai';
import Inconvo from '@inconvoai/node';
import { inconvoDataAgent } from '@inconvoai/vercel-ai-sdk';

// Initialize Inconvo client
const inconvo = new Inconvo({
  apiKey: process.env.INCONVO_API_KEY,
});

export async function POST(req: Request) {
  try {
    const { messages } = await req.json();

    // Get the last user message
    const lastMessage = messages[messages.length - 1];

    if (!lastMessage || lastMessage.role !== 'user') {
      return new Response('Invalid message format', { status: 400 });
    }

    // Get Inconvo agent ID from environment
    const agentId = process.env.INCONVO_AGENT_ID;
    if (!agentId) {
      return new Response('INCONVO_AGENT_ID environment variable is not set', { 
        status: 500 
      });
    }

    // Create a new conversation or use existing one
    // For simplicity, we'll start a new conversation for each request
    // In production, you'd want to manage conversation IDs in state
    const conversation = await inconvo.agents.conversations.create(agentId, {
      userIdentifier: 'default-user',
    });

    // Get Inconvo tools
    const tools = inconvoDataAgent({
      inconvo,
      agentId,
      userIdentifier: 'default-user',
    });

    // Stream the response using Vercel AI SDK
    const result = streamText({
      model: inconvo as any, // Type assertion for compatibility
      messages,
      tools,
      maxSteps: 5,
    });

    return result.toDataStreamResponse();
  } catch (error) {
    console.error('Error in chat route:', error);
    return new Response(
      JSON.stringify({ error: 'Failed to process chat message' }),
      { 
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      }
    );
  }
}

